object WebhookProxyService {

  // Allowlisted domains for partner APIs
  private val allowlistedDomains: Set[String] = Set(
    "api.partner1.com",
    "api.partner2.com",
    "hooks.partner3.io",
    "webhook.partner4.net"
  )

  // Maximum number of redirects to follow (tightly controlled)
  private val maxRedirects: Int = 3

  /**
   * Checks if an IP address is in a private, loopback, link-local, or multicast range.
   * Returns true if the address is blocked (internal/private).
   */
  def isBlockedIpAddress(address: InetAddress): Boolean = {
    address.isLoopbackAddress ||
      address.isLinkLocalAddress ||
      address.isMulticastAddress ||
      address.isAnyLocalAddress ||
      address.isSiteLocalAddress ||
      isPrivateRange(address) ||
      isMetadataAddress(address)
  }

  /**
   * Explicitly checks for RFC1918 private ranges and other dangerous ranges.
   */
  private def isPrivateRange(address: InetAddress): Boolean = {
    val bytes = address.getAddress
    if (bytes.length == 4) {
      val b0 = bytes(0) & 0xFF
      val b1 = bytes(1) & 0xFF

      // 10.0.0.0/8
      if (b0 == 10) return true
      // 172.16.0.0/12
      if (b0 == 172 && b1 >= 16 && b1 <= 31) return true
      // 192.168.0.0/16
      if (b0 == 192 && b1 == 168) return true
      // 127.0.0.0/8 (loopback, extra check)
      if (b0 == 127) return true
      // 169.254.0.0/16 (link-local, extra check)
      if (b0 == 169 && b1 == 254) return true
      // 0.0.0.0/8
      if (b0 == 0) return true
      // 100.64.0.0/10 (Carrier-grade NAT)
      if (b0 == 100 && b1 >= 64 && b1 <= 127) return true
      // 192.0.0.0/24 (IETF Protocol Assignments)
      if (b0 == 192 && b1 == 0 && (bytes(2) & 0xFF) == 0) return true
    } else if (bytes.length == 16) {
      // IPv6 loopback ::1
      val isLoopback = bytes.take(15).forall(_ == 0) && bytes(15) == 1
      if (isLoopback) return true
      // IPv6 link-local fe80::/10
      if ((bytes(0) & 0xFF) == 0xFE && (bytes(1) & 0xC0) == 0x80) return true
      // IPv6 unique local fc00::/7
      if ((bytes(0) & 0xFE) == 0xFC) return true
      // IPv4-mapped IPv6 addresses ::ffff:x.x.x.x - check the embedded IPv4
      val isV4Mapped = bytes.take(10).forall(_ == 0) &&
        (bytes(10) & 0xFF) == 0xFF && (bytes(11) & 0xFF) == 0xFF
      if (isV4Mapped) {
        val v4Bytes = bytes.drop(12)
        val v4Addr = InetAddress.getByAddress(v4Bytes)
        return isBlockedIpAddress(v4Addr)
      }
    }
    false
  }

  /**
   * Checks specifically for cloud metadata service addresses.
   */
  private def isMetadataAddress(address: InetAddress): Boolean = {
    val hostAddr = address.getHostAddress
    // AWS/GCP/Azure metadata endpoints
    hostAddr == "169.254.169.254" ||
      hostAddr == "fd00:ec2::254" ||
      hostAddr == "metadata.google.internal"
  }

  /**
   * Validates a URL against the allowlist and resolves DNS to check for private IPs.
   * Returns Right(validatedUri) or Left(errorMessage).
   */
  def validateUrl(urlString: String)(implicit ec: ExecutionContext): Future[Either[String, Uri]] = {
    Future {
      Try(new URI(urlString)) match {
        case Failure(_) =>
          Left(s"Invalid URL format: $urlString")

        case Success(uri) =>
          // Ensure scheme is HTTPS only
          val scheme = Option(uri.getScheme).map(_.toLowerCase).getOrElse("")
          if (scheme != "https") {
            Left(s"Only HTTPS scheme is allowed, got: $scheme")
          } else {
            val host = Option(uri.getHost).map(_.toLowerCase).getOrElse("")

            if (host.isEmpty) {
              Left("URL must contain a valid host")
            } else if (!allowlistedDomains.contains(host)) {
              Left(s"Host '$host' is not in the allowlist. Allowed: ${allowlistedDomains.mkString(", ")}")
            } else {
              // Resolve DNS and check all resolved IPs
              Try(InetAddress.getAllByName(host)) match {
                case Failure(ex) =>
                  Left(s"DNS resolution failed for host '$host': ${ex.getMessage}")

                case Success(addresses) if addresses.isEmpty =>
                  Left(s"No addresses resolved for host '$host'")

                case Success(addresses) =>
                  val blockedAddresses = addresses.filter(isBlockedIpAddress)
                  if (blockedAddresses.nonEmpty) {
                    Left(s"Host '$host' resolves to blocked IP address(es): ${blockedAddresses.map(_.getHostAddress).mkString(", ")}")
                  } else {
                    Right(Uri(urlString))
                  }
              }
            }
          }
      }
    }
  }

  /**
   * Validates a redirect location against the same security rules.
   */
  def validateRedirectLocation(location: String, originalHost: String)(implicit ec: ExecutionContext): Future[Either[String, Uri]] = {
    Future {
      Try(new URI(location)) match {
        case Failure(_) =>
          Left(s"Invalid redirect URL: $location")

        case Success(uri) =>
          val scheme = Option(uri.getScheme).map(_.toLowerCase).getOrElse("")
          val host = Option(uri.getHost).map(_.toLowerCase).getOrElse("")

          if (scheme != "https") {
            Left(s"Redirect to non-HTTPS scheme blocked: $scheme")
          } else if (!allowlistedDomains.contains(host)) {
            Left(s"Redirect to non-allowlisted host blocked: $host")
          } else {
            Try(InetAddress.getAllByName(host)) match {
              case Failure(ex) =>
                Left(s"DNS resolution failed for redirect host '$host': ${ex.getMessage}")
              case Success(addresses) =>
                val blockedAddresses = addresses.filter(isBlockedIpAddress)
                if (blockedAddresses.nonEmpty) {
                  Left(s"Redirect host '$host' resolves to blocked IP: ${blockedAddresses.map(_.getHostAddress).mkString(", ")}")
                } else {
                  Right(Uri(location))
                }
            }
          }
      }
    }
  }

  /**
   * Fetches content from a validated URL, handling redirects securely.
   */
  def fetchWithRedirectControl(
    uri: Uri,
    remainingRedirects: Int
  )(implicit system: ActorSystem, ec: ExecutionContext, mat: Materializer): Future[Either[String, HttpResponse]] = {
    // Disable automatic redirect following - we handle it manually
    Http().singleRequest(HttpRequest(uri = uri)).flatMap { response =>
      response.status match {
        case StatusCodes.MovedPermanently | StatusCodes.Found |
             StatusCodes.SeeOther | StatusCodes.TemporaryRedirect |
             StatusCodes.PermanentRedirect =>

          // Discard the response entity to free connection
          response.discardEntityBytes()

          if (remainingRedirects <= 0) {
            Future.successful(Left("Too many redirects"))
          } else {
            response.header[headers.Location] match {
              case Some(locationHeader) =>
                val redirectUrl = locationHeader.uri.toString()
                val originalHost = uri.authority.host.address()

                validateRedirectLocation(redirectUrl, originalHost).flatMap {
                  case Left(error) =>
                    Future.successful(Left(s"Redirect blocked: $error"))
                  case Right(validatedRedirectUri) =>
                    // Re-resolve DNS for the redirect target to prevent TOCTOU
                    revalidateAndFetch(validatedRedirectUri, remainingRedirects - 1)
                }

              case None =>
                Future.successful(Left("Redirect response missing Location header"))
            }
          }

        case _ =>
          Future.successful(Right(response))
      }
    }.recover {
      case ex: Exception =>
        Left(s"Request failed: ${ex.getMessage}")
    }
  }

  /**
   * Re-resolves DNS and re-validates before following a redirect (prevents TOCTOU attacks).
   */
  private def revalidateAndFetch(
    uri: Uri,
    remainingRedirects: Int
  )(implicit system: ActorSystem, ec: ExecutionContext, mat: Materializer): Future[Either[String, HttpResponse]] = {
    val host = uri.authority.host.address()

    Future {
      Try(InetAddress.getAllByName(host)) match {
        case Failure(ex) =>
          Left(s"DNS re-resolution failed for '$host': ${ex.getMessage}")
        case Success(addresses) =>
          val blockedAddresses = addresses.filter(isBlockedIpAddress)
          if (blockedAddresses.nonEmpty) {
            Left(s"Re-resolved host '$host' points to blocked IP: ${blockedAddresses.map(_.getHostAddress).mkString(", ")}")
          } else {
            Right(uri)
          }
      }
    }.flatMap {
      case Left(error) => Future.successful(Left(error))
      case Right(validUri) => fetchWithRedirectControl(validUri, remainingRedirects)
    }
  }

  def main(args: Array[String]): Unit = {
    implicit val system: ActorSystem = ActorSystem("webhook-proxy")
    implicit val ec: ExecutionContext = system.dispatcher

    val route: Route =
      path("proxy") {
        post {
          entity(Unmarshaller.messageUnmarshallerFromEntityUnmarshaller(Unmarshaller.stringUnmarshaller)) { urlString =>
            val trimmedUrl = urlString.trim

            val resultFuture: Future[(StatusCode, String)] = validateUrl(trimmedUrl).flatMap {
              case Left(error) =>
                Future.successful((StatusCodes.BadRequest, s"""{"error": "$error"}"""))

              case Right(validatedUri) =>
                fetchWithRedirectControl(validatedUri, maxRedirects).flatMap {
                  case Left(error) =>
                    Future.successful((StatusCodes.BadGateway, s"""{"error": "$error"}"""))

                  case Right(response) =>
                    import akka.http.scaladsl.unmarshalling.Unmarshal
                    Unmarshal(response.entity).to[String].map { body =>
                      val statusCode = response.status.intValue()
                      (StatusCodes.OK,
                        s"""{"status": $statusCode, "content_length": ${body.length}, "content": ${escapeJson(body)}}""")
                    }.recover {
                      case ex =>
                        (StatusCodes.BadGateway, s"""{"error": "Failed to read response body: ${ex.getMessage}"}""")
                    }
                }
            }

            onComplete(resultFuture) {
              case Success((status, body)) =>
                complete(HttpResponse(
                  status = status,
                  entity = HttpEntity(ContentTypes.`application/json`, body)
                ))
              case Failure(ex) =>
                complete(HttpResponse(
                  status = StatusCodes.InternalServerError,
                  entity = HttpEntity(ContentTypes.`application/json`,
                    s"""{"error": "Internal error: ${escapeJsonString(ex.getMessage)}"}""")
                ))
            }
          }
        }
      } ~
        path("health") {
          get {
            complete(HttpResponse(
              status = StatusCodes.OK,
              entity = HttpEntity(ContentTypes.`application/json`,
                s"""{"status": "healthy", "allowlisted_domains": [${allowlistedDomains.map(d => s""""$d"""").mkString(",")}]}""")
            ))
          }
        }

    val bindingFuture = Http().newServerAt("0.0.0.0", 8080).bind(route)

    bindingFuture.onComplete {
      case Success(binding) =>
        val address = binding.localAddress
        println(s"Webhook proxy service listening on ${address.getHostString}:${address.getPort}")
        println(s"Allowlisted domains: ${allowlistedDomains.mkString(", ")}")
        println(s"Max redirects: $maxRedirects")
      case Failure(ex) =>
        println(s"Failed to bind: ${ex.getMessage}")
        system.terminate()
    }
  }

  private def escapeJson(s: String): String = {
    "\"" + escapeJsonString(s) + "\""
  }

  private def escapeJsonString(s: String): String = {
    if (s == null) return ""
    s.replace("\\", "\\\\")
      .replace("\"", "\\\"")
      .replace("\n", "\\n")
      .replace("\r", "\\r")
      .replace("\t", "\\t")
      .replace("\b", "\\b")
      .replace("\f", "\\f")
  }
